module alu_32bit(obf_A, B, opcode, result);
    input [31:0] obf_A;
    input [31:0] B;
    input [2:0] opcode;
    output reg [31:0] result;

    always @(*) begin
        case (opcode)
            3'b000: result = obf_A + B;   // Addition
            3'b001: result = obf_A - B;   // Subtraction
            3'b010: result = obf_A & B;   // AND
            3'b011: result = obf_A | B;   // OR
            3'b100: result = obf_A ^ B;   // XOR
            default: result = 32'b0;  // Default case
        endcase
    end
endmodule
